('09fbc741-6742-4a66-bcc6-aa417dcac326', '09fec532-ca96-43c6-a8c5-fc744984cc47', '1', '{"title": "报告外发123456", "rating": "OUTPERFORM", "ticker": "VST US", "analysts": [{"role": 1, "analyst_id": "58020af7-0844-471d-ad19-6b66a73178b6", "sort_order": 1}, {"role": 2, "analyst_id": "431bcf7b-3108-4d1d-9b32-62616f72f1c1", "sort_order": 2}], "sector_id": null, "coverage_id": "57ed4bf9-b4ac-485d-a3a5-5891f02d7c95", "region_code": null, "report_type": "company", "target_price": "123.45", "report_language": "en", "contact_person_id": null, "investment_thesis": "<p>测试报告12121212121</p><p>1111111111111111</p><p>大苏打撒旦</p>", "certificate_confirmed": true}', '09fec532-ca96-43c6-a8c5-fc744984cc47/09fec532-ca96-43c6-a8c5-fc744984cc47_001_report_2026-04-01T10-54-05-415Z_EN-Vistra_Corp20260104.docx', '09fec532-ca96-43c6-a8c5-fc744984cc47/09fec532-ca96-43c6-a8c5-fc744984cc47_001_model_2026-04-01T10-54-06-067Z_Financial_Summary.xls', '6de69f70-b17a-48e1-8e49-3efa86b68c40', '2026-04-01 18:54:06.11023+08', '2026-04-01 18:54:06.11023+08', 'EN-Vistra Corp20260104.docx', 'Financial Summary.xls', null, null);
