('62a8e81e-07dc-4715-bf63-8ddcaf2aaf98', 'fde8295c-bb2e-4cd9-8a69-23a63c1f6f5f', '1', '{"title": "test title", "rating": null, "ticker": null, "analysts": [], "sector_id": null, "coverage_id": null, "region_code": null, "report_type": "company", "target_price": null, "report_language": "en", "contact_person_id": null, "investment_thesis": null, "certificate_confirmed": false}', null, null, '6de69f70-b17a-48e1-8e49-3efa86b68c40', '2026-03-30 12:03:37.406011+08', '2026-03-30 12:03:37.406011+08', null, null, null, null);
