('6ebc7c9d-c005-4649-9921-74e08ea299e0', '8d227125-3ac2-4002-809b-7c8209f065f2', '2', '{"title": "本地和服务器轮询都停止了", "rating": "OUTPERFORM", "ticker": "VST US", "analysts": [{"role": 1, "analyst_id": "58020af7-0844-471d-ad19-6b66a73178b6", "sort_order": 1}, {"role": 2, "analyst_id": "431bcf7b-3108-4d1d-9b32-62616f72f1c1", "sort_order": 2}], "sector_id": null, "coverage_id": "57ed4bf9-b4ac-485d-a3a5-5891f02d7c95", "region_code": null, "report_type": "company", "target_price": "123.45", "report_language": "zh", "contact_person_id": null, "investment_thesis": "<p>测试打赏的撒旦阿斯顿阿斯顿阿斯顿</p><p></p><p>dasdasddsadasdadasdasdadasd</p><p></p><p>1212131231114566464564646</p>", "certificate_confirmed": true}', '8d227125-3ac2-4002-809b-7c8209f065f2/8d227125-3ac2-4002-809b-7c8209f065f2_002_report_2026-04-01T12-02-13-321Z_EN-Vistra_Corp20260104.docx', null, '6de69f70-b17a-48e1-8e49-3efa86b68c40', '2026-04-01 20:02:14.551625+08', '2026-04-01 20:02:14.551625+08', 'EN-Vistra Corp20260104.docx', null, '8d227125-3ac2-4002-809b-7c8209f065f2/8d227125-3ac2-4002-809b-7c8209f065f2_002_report-pdf_2026-04-01T12-02-14-651Z_EN-Vistra_Corp20260104_AutoRefresh.pdf', 'EN-Vistra+Corp20260104_AutoRefresh.pdf');
