('b7868178-f9d2-4d4f-b1fc-d72020f6e4ac', '5dcb47dc-5489-43ff-9433-37323eb04a76', '2', '{"title": "再次同步报告测试", "rating": "OUTPERFORM", "ticker": "VST US", "analysts": [{"role": 1, "analyst_id": "58020af7-0844-471d-ad19-6b66a73178b6", "sort_order": 1}, {"role": 2, "analyst_id": "431bcf7b-3108-4d1d-9b32-62616f72f1c1", "sort_order": 2}], "sector_id": null, "coverage_id": "57ed4bf9-b4ac-485d-a3a5-5891f02d7c95", "region_code": null, "report_type": "company", "target_price": "234.15", "report_language": "zh", "contact_person_id": null, "investment_thesis": "<p>测试报告撒打算大撒阿斯顿收到阿斯顿 阿萨的阿斯顿</p><p></p><p>121212121  titsdsdsdsdsds</p>", "certificate_confirmed": true}', '5dcb47dc-5489-43ff-9433-37323eb04a76/5dcb47dc-5489-43ff-9433-37323eb04a76_002_report_2026-04-01T11-35-38-432Z_EN-Vistra_Corp20260104.docx', null, '6de69f70-b17a-48e1-8e49-3efa86b68c40', '2026-04-01 19:35:39.663068+08', '2026-04-01 19:35:39.663068+08', 'EN-Vistra Corp20260104.docx', null, '5dcb47dc-5489-43ff-9433-37323eb04a76/5dcb47dc-5489-43ff-9433-37323eb04a76_002_report-pdf_2026-04-01T11-35-39-967Z_EN-Vistra_Corp20260104_AutoRefresh.pdf', 'EN-Vistra+Corp20260104_AutoRefresh.pdf');
